const CsvToArray = type("string").pipe((s, ctx) => {
  const lines = s.split(/\r?\n/).filter(line => line !== "");
  if (lines.length === 0) {
    return ctx.error("Empty input (no header row)");
  }
  if (lines[0] !== "id,age,email,signupAt") {
    return ctx.error("Malformed header");
