      return ctx.error(`Row ${i} has wrong number of columns (expected 4, got ${cells.length})`);
    }
    objects.push({
      id: cells[0],
      age: cells[1],
      email: cells[2],
      signupAt: cells[3]
    });
  }
  return objects;
});

